import sysfrom pathlib import Pathfrom typing import Anyimport numpy as npimport pandas as pd# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import INTERIM_DATA_DIR, PROCESSED_DATA_DIRLABEL_WINDOW = "5d"SPLITS = ["train", "validation", "test"]def extract_label(label_obj: Any, window: str = LABEL_WINDOW):    """    Extract the filing-level label for a given window from the labels dict.    In this dataset, labels are usually encoded as:        {"1d": 0/1, "5d": 0/1, "30d": 0/1}    Returns:        int or np.nan    """    if not isinstance(label_obj, dict):        return np.nan    value = label_obj.get(window, np.nan)    # Keep as integer if possible    if pd.isna(value):        return np.nan    try:        return int(value)    except Exception:        return np.nandef aggregate_sections(df: pd.DataFrame) -> pd.DataFrame:    """    Create a compact section summary per docID:    - number of unique sections    - ordered list of section names    """    sec_df = (        df[["docID", "section_name", "sentenceCount"]]        .sort_values(["docID", "sentenceCount"])        .drop_duplicates(subset=["docID", "section_name"])        .groupby("docID", as_index=False)["section_name"]        .agg(list)        .rename(columns={"section_name": "section_list"})    )    sec_df["n_sections"] = sec_df["section_list"].apply(len)    return sec_dfdef build_document_level(df: pd.DataFrame, split_name: str) -> pd.DataFrame:    """    Convert sentence-level dataframe to document-level dataframe.    """    required_cols = {        "docID",        "sentence",        "sentenceCount",        "labels",        "filingDate",        "cik",        "section_name",    }    missing = required_cols - set(df.columns)    if missing:        raise ValueError(f"[{split_name}] Missing required columns: {missing}")    # Sort by document and sentence order before concatenating text    df = df.sort_values(["docID", "sentenceCount"]).copy()    # Build full document text    docs = (        df.groupby("docID", as_index=False)["sentence"]        .agg(lambda s: " ".join(s.astype(str)))        .rename(columns={"sentence": "full_text"})    )    # Keep one row of metadata per docID    metadata_cols = [        "docID",        "cik",        "filingDate",        "name",        "entityType",        "sic",        "stateOfIncorporation",        "form",        "reportDate",    ]    metadata_cols = [c for c in metadata_cols if c in df.columns]    meta = df[metadata_cols].drop_duplicates(subset=["docID"]).copy()    # Extract label    lab = (        df[["docID", "labels"]]        .drop_duplicates(subset=["docID"])        .copy()    )    lab[f"label_{LABEL_WINDOW}"] = lab["labels"].apply(        lambda x: extract_label(x, LABEL_WINDOW)    )    lab = lab.drop(columns=["labels"])    # Section summary    sec = aggregate_sections(df)    # Sentence count per document    sent_stats = (        df.groupby("docID", as_index=False)["sentence"]        .size()        .rename(columns={"size": "n_sentences"})    )    # Merge all components    doc_df = docs.merge(meta, on="docID", how="left")    doc_df = doc_df.merge(lab, on="docID", how="left")    doc_df = doc_df.merge(sec, on="docID", how="left")    doc_df = doc_df.merge(sent_stats, on="docID", how="left")    # Clean filingDate    if "filingDate" in doc_df.columns:        doc_df["filingDate"] = pd.to_datetime(doc_df["filingDate"], errors="coerce")    # Drop rows with missing label or text    before = len(doc_df)    doc_df = doc_df.dropna(subset=["full_text", f"label_{LABEL_WINDOW}"]).copy()    after = len(doc_df)    # Convert label to int    doc_df[f"label_{LABEL_WINDOW}"] = doc_df[f"label_{LABEL_WINDOW}"].astype(int)    print(f"\n[{split_name}] Document-level rows before dropna: {before}")    print(f"[{split_name}] Document-level rows after dropna:  {after}")    print(f"[{split_name}] Label distribution:")    print(doc_df[f"label_{LABEL_WINDOW}"].value_counts(dropna=False).sort_index())    return doc_dfdef save_document_split(doc_df: pd.DataFrame, split_name: str) -> Path:    """    Save document-level split to data/processed.    """    out_path = PROCESSED_DATA_DIR / f"{split_name}_doc_{LABEL_WINDOW}.parquet"    doc_df.to_parquet(out_path, index=False)    return out_pathdef main():    PROCESSED_DATA_DIR.mkdir(parents=True, exist_ok=True)    saved_paths = []    for split_name in SPLITS:        in_path = INTERIM_DATA_DIR / f"{split_name}_sent_small_full.parquet"        print(f"\n==============================")        print(f"Processing split: {split_name}")        print(f"Input: {in_path}")        print(f"==============================")        if not in_path.exists():            raise FileNotFoundError(f"Input file not found: {in_path}")        print("Loading sentence-level parquet...")        df = pd.read_parquet(in_path)        print("Building document-level dataframe...")        doc_df = build_document_level(df, split_name)        print("\nSample document-level rows:")        print(doc_df.head(3)[["docID", "label_5d", "n_sentences", "n_sections"]])        out_path = save_document_split(doc_df, split_name)        saved_paths.append(out_path)        print(f"Saved: {out_path}")    print("\nAll document-level splits saved successfully.")    print("\nSaved files:")    for p in saved_paths:        print(p)if __name__ == "__main__":    main()